module bug (
    input logic wr_clk,
    input logic wr_data,
    output logic [1:0] mem
);
`ifdef CASE_1
  always_ff @(posedge (wr_clk)) begin
      mem[0] <= wr_data;
  end
  always_ff @(posedge (wr_clk)) begin
      mem[1] <= wr_data;
  end
`else
  always_ff @(posedge (wr_clk)) begin
      mem[0] <= wr_data;
      mem[1] <= wr_data;
  end
`endif
endmodule
