    %0 = comb.replicate %wr_data : (i1) -> i2 loc(#loc4)
    %1 = seq.to_clock %wr_clk loc(#loc5)
    %mem = seq.firreg %0 clock %1 : i2 loc(#loc5)
    hw.output %mem : i2 loc(#loc1)
